const DEFAULT_SETTINGS = {
  openInNewTab: false,
  theme: "original", // "original", "dark", or "custom"
  customTheme: {
    bg: "#10131a",
    surface: "#1d2230",
    copy: "#f79a1c"
  },
  volumeBoost: 100,
  playbackSpeed: 1
};

const openInNewTabInput = document.getElementById("openInNewTab");
const themeInputs = document.querySelectorAll('input[name="theme"]');
const customThemePanel = document.getElementById("customThemePanel");
const colorInputs = {
  bg: document.getElementById("colorBg"),
  surface: document.getElementById("colorSurface"),
  copy: document.getElementById("colorCopy")
};
const volumeBoostInput = document.getElementById("volumeBoost");
const volumeValueOutput = document.getElementById("volumeValue");

let settings = { ...DEFAULT_SETTINGS };

function getStoredSettings() {
  return new Promise((resolve) => {
    chrome.storage.local.get(DEFAULT_SETTINGS, (stored) => {
      resolve({ ...DEFAULT_SETTINGS, ...stored });
    });
  });
}

function setStoredSettings(nextSettings) {
  return new Promise((resolve) => {
    chrome.storage.local.set(nextSettings, () => resolve());
  });
}

function updateTheme() {
  document.body.dataset.theme = settings.theme === "original" ? "light" : "dark";
}

function updateVolumeLabel() {
  volumeValueOutput.textContent = `${settings.volumeBoost}%`;
}

function syncInputsWithSettings() {
  openInNewTabInput.checked = settings.openInNewTab;

  themeInputs.forEach(input => {
    input.checked = input.value === settings.theme;
  });

  if (settings.theme === "custom") {
    customThemePanel.classList.add("expanded");
  } else {
    customThemePanel.classList.remove("expanded");
  }

  Object.entries(colorInputs).forEach(([key, input]) => {
    if (input && settings.customTheme[key]) {
      input.value = settings.customTheme[key];
    }
  });

  volumeBoostInput.value = String(settings.volumeBoost);
  updateTheme();
  updateVolumeLabel();
}

async function saveAndRender(nextSettings) {
  settings = { ...settings, ...nextSettings };
  await setStoredSettings(nextSettings);
  syncInputsWithSettings();
}

async function initialize() {
  settings = await getStoredSettings();
  syncInputsWithSettings();

  openInNewTabInput.addEventListener("change", async (event) => {
    await saveAndRender({ openInNewTab: event.target.checked });
  });

  themeInputs.forEach(input => {
    input.addEventListener("change", async (event) => {
      await saveAndRender({ theme: event.target.value });
    });
  });

  Object.entries(colorInputs).forEach(([key, input]) => {
    if (input) {
      const handleColorChange = async (event) => {
        const newCustomTheme = { ...settings.customTheme, [key]: event.target.value };
        await saveAndRender({ customTheme: newCustomTheme });
      };
      input.addEventListener("input", handleColorChange);
      input.addEventListener("change", handleColorChange);
    }
  });

  volumeBoostInput.addEventListener("input", async (event) => {
    const numericValue = Number(event.target.value);
    const clamped = Number.isFinite(numericValue)
      ? Math.max(0, Math.min(300, numericValue))
      : DEFAULT_SETTINGS.volumeBoost;

    await saveAndRender({ volumeBoost: clamped });
  });
}

initialize();

:root {
  /* Primary scale from uicolors: https://uicolors.app/generate/FFA100 */
  --brand-50: #fff8eb;
  --brand-100: #ffefd5;
  --brand-200: #ffd7a3;
  --brand-300: #ffbc65;
  --brand-400: #fca52f;
  --brand-500: #f7991c;
  --brand-600: #db7e0e;
  --brand-700: #b45f0c;
  --brand-800: #8d470f;
  --brand-900: #743b10;
  --brand-950: #3f1c06;

  --light-bg: #fffefb;
  --light-panel: #ffffff;
  --light-border: #f3cf9b;
  --light-copy: #3b2915;
  --light-muted: #7a6348;

  --dark-bg: #10131a;
  --dark-panel: #1d2230;
  --dark-border: #333d4f;
  --dark-copy: #f79a1c;
  --dark-muted: #a2a9b8;
  --dark-accent: #ffa100;
  --dark-accent-deep: #db7e0e;
}

*,
*::before,
*::after {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  width: 360px;
}

body {
  font-family: "Audible Sans", "Helvetica Neue", Arial, sans-serif;
  background:
    radial-gradient(circle at 10% 0%, rgba(247, 153, 28, 0.26), transparent 40%),
    radial-gradient(circle at 90% 10%, rgba(252, 165, 47, 0.2), transparent 45%),
    var(--background);
  color: var(--text);
  padding: 14px;
}

body[data-theme="light"] {
  --background: var(--light-bg);
  --panel: var(--light-panel);
  --text: var(--light-copy);
  --text-muted: var(--light-muted);
  --border: var(--light-border);
  --shadow: 0 18px 34px -22px rgba(95, 56, 11, 0.4);
}

body[data-theme="dark"] {
  --background: var(--dark-bg);
  --panel: var(--dark-panel);
  --text: var(--dark-copy);
  --text-muted: var(--dark-muted);
  --border: rgba(51, 61, 79, 0.5); /* webplayer border with opacity */
  --shadow: 0 18px 34px -18px rgba(0, 0, 0, 0.6);
  background: var(--background);
}

.panel {
  border-radius: 16px;
  border: 1px solid var(--border);
  background: var(--panel);
  box-shadow: var(--shadow);
  overflow: hidden;
}

.panel-header {
  padding: 16px 16px 14px;
  background:
    linear-gradient(160deg, rgba(255, 188, 101, 0.45), rgba(247, 153, 28, 0.08)),
    var(--panel);
  border-bottom: 1px solid var(--border);
}

body[data-theme="dark"] .panel-header {
  background: var(--panel);
}

.kicker {
  margin: 0 0 6px;
  font-size: 11px;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--text-muted);
}

h1 {
  margin: 0;
  font-family: "Audible Sans", "Helvetica Neue", Arial, sans-serif;
  font-size: 24px;
  line-height: 1.15;
  font-weight: 700;
}

.subtitle {
  margin: 6px 0 0;
  color: var(--text-muted);
  font-size: 13px;
}

.panel-body {
  padding: 8px 12px 12px;
}

.setting-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  padding: 10px 8px;
}

.setting-copy h2 {
  margin: 0;
  font-size: 14px;
  line-height: 1.2;
}

.setting-copy p {
  margin: 4px 0 0;
  color: var(--text-muted);
  font-size: 12px;
}

.switch {
  position: relative;
  display: inline-flex;
  align-items: center;
  width: 46px;
  min-width: 46px;
  height: 26px;
}

.switch input {
  position: absolute;
  opacity: 0;
  width: 0;
  height: 0;
}

.slider {
  position: absolute;
  inset: 0;
  border-radius: 999px;
  border: 1px solid var(--border);
  background: rgba(127, 99, 62, 0.16);
  transition: background 180ms ease, border-color 180ms ease;
}

.slider::before {
  content: "";
  position: absolute;
  left: 3px;
  top: 3px;
  width: 18px;
  height: 18px;
  border-radius: 50%;
  background: #ffffff;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.24);
  transition: transform 180ms ease;
}

.switch input:checked + .slider {
  background: linear-gradient(135deg, var(--brand-300), var(--brand-600));
  border-color: transparent;
}

body[data-theme="dark"] .switch input:checked + .slider {
  background: linear-gradient(
    135deg,
    var(--dark-accent),
    var(--dark-accent-deep)
  );
}

.switch input:checked + .slider::before {
  transform: translateX(20px);
}

.theme-picker {
  display: flex;
  gap: 8px;
  padding: 0 8px 12px;
}

.theme-option {
  flex: 1;
  position: relative;
  cursor: pointer;
}

.theme-option input {
  position: absolute;
  opacity: 0;
  width: 0;
  height: 0;
}

.theme-label {
  display: block;
  text-align: center;
  padding: 6px 10px;
  font-size: 13px;
  font-weight: 500;
  border-radius: 8px;
  border: 1px solid var(--border);
  background: var(--panel);
  color: var(--text-muted);
  transition: all 180ms ease;
  user-select: none;
}

.theme-option input:checked + .theme-label {
  color: #fff;
  border-color: transparent;
  background: linear-gradient(135deg, var(--brand-300), var(--brand-600));
}

body[data-theme="dark"] .theme-option input:checked + .theme-label {
  background: linear-gradient(135deg, var(--dark-accent), var(--dark-accent-deep));
}

.custom-theme-panel {
  max-height: 0;
  overflow: hidden;
  opacity: 0;
  transition: max-height 300ms ease, opacity 300ms ease, margin 300ms ease, padding 300ms ease;
  background: rgba(0, 0, 0, 0.03);
  border-radius: 12px;
  border: 1px solid transparent;
  margin: 0 8px;
}

body[data-theme="dark"] .custom-theme-panel {
  background: rgba(0, 0, 0, 0.2);
}

.custom-theme-panel.expanded {
  max-height: 250px;
  opacity: 1;
  padding: 12px;
  margin-bottom: 12px;
  border-color: var(--border);
}

.color-row {
  display: flex;
  align-items: center;

