      <input class="${SPEED_POPOVER_RANGE_CLASS}" type="range" min="${Math.round(PLAYBACK_SPEED_MIN * 100)}" max="${Math.round(PLAYBACK_SPEED_MAX * 100)}" step="${Math.round(PLAYBACK_SPEED_STEP * 100)}" />
