  }

  const stepButtons = popover.querySelectorAll("button.audible-tools-speed-popover-step");
  stepButtons.forEach((button) => {
    button.addEventListener("click", () => {
      const direction = button.getAttribute("data-step") === "+" ? 1 : -1;
