  ensureSpeedPopover();
  syncSpeedPopoverUi();
  applyPlaybackSpeed(currentSettings.playbackSpeed);
  ensureVolumeWidget();
  syncVolumeWidget();
  applyVolumeBoost(currentSettings.volumeBoost);
  applyDarkModeToPage(currentSettings.theme, currentSettings.customTheme);
